//! `rpcs3-lv2-syscall-table` — frozen PS3 LV2 syscall table.
//!
//! Mirrors `rpcs3/Emu/Cell/lv2/lv2.cpp:141-965` (`g_ppu_syscall_table`).
//! This table is **ABI-critical**: every game's syscalls dispatch through
//! these 1024 slots. Any reordering breaks compatibility with every
//! existing game and every RPCS3 savestate.
//!
//! Generated by `rust/rpcs3-lv2-syscall-table/gen.py`.

/// A single syscall table slot.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum SyscallSlot {
    /// `null_func` in C++ — slot exists but has no binding.
    Null,
    /// `uns_func` in C++ — slot is officially "Unused".
    Unused,
    /// Normal `BIND_SYSC(name)` binding with an HLE implementation.
    Bound(&'static str),
    /// `NULL_FUNC(name)` — symbol is named but has no HLE impl.
    NullFunc(&'static str),
}

impl SyscallSlot {
    /// Returns the syscall's symbolic name, or `None` if the slot
    /// is unbound (Null or Unused).
    #[must_use]
    pub const fn name(&self) -> Option<&'static str> {
        match self {
            SyscallSlot::Null | SyscallSlot::Unused => None,
            SyscallSlot::Bound(n) | SyscallSlot::NullFunc(n) => Some(n),
        }
    }

    /// True if the slot has a real HLE implementation.
    #[must_use]
    pub const fn is_bound(&self) -> bool {
        matches!(self, SyscallSlot::Bound(_))
    }
}

/// Look up a slot by its 16-bit syscall id.
#[must_use]
pub fn lookup(id: u16) -> Option<&'static SyscallSlot> {
    SYSCALL_TABLE.get(id as usize)
}

/// Reverse lookup: find the id of a syscall by name.
#[must_use]
pub fn find_by_name(name: &str) -> Option<u16> {
    SYSCALL_TABLE.iter().enumerate().find_map(|(i, slot)| match slot.name() {
        Some(n) if n == name => Some(i as u16),
        _ => None,
    })
}

